request.query:
#graphql
  mutation MetaobjectUpsertRecoveryDefinitionCreate($definition: MetaobjectDefinitionCreateInput!) {
    metaobjectDefinitionCreate(definition: $definition) {
      metaobjectDefinition {
        id
        type
        name
        displayNameKey
        fieldDefinitions {
          key
          name
          required
          type {
            name
            category
          }
        }
      }
      userErrors {
        field
        message
        code
      }
    }
  }

fragment MetaobjectUpsertRecoveryFields on Metaobject {
  id
  handle
  type
  displayName
  updatedAt
  capabilities {
    publishable {
      status
    }
    onlineStore {
      templateSuffix
    }
  }
  fields {
    key
    type
    value
    jsonValue
    definition {
      key
      name
      required
      type {
        name
        category
      }
    }
  }
  titleField: field(key: "title") {
    key
    type
    value
    jsonValue
    definition {
      key
      name
      required
      type {
        name
        category
      }
    }
  }
}

mutation MetaobjectUpsertRecoveryAndPrefixes($handle: MetaobjectHandleInput!, $metaobject: MetaobjectUpsertInput!) {
  metaobjectUpsert(handle: $handle, metaobject: $metaobject) {
    metaobject {
      ...MetaobjectUpsertRecoveryFields
    }
    userErrors {
      field
      message
